where r.is_deleted = 0

    and r.task_id = #{taskId}


    and t.semester_id = #{semesterId}


    and t.class_id = #{classId}


    and r.objective_id = #{objectiveId}


    and r.model_id = #{modelId}


    and r.locked_flag = #{lockedFlag}


    and (
        t.task_code like concat('%', #{keyword}, '%')
        or c.course_name like concat('%', #{keyword}, '%')
        or c.course_code like concat('%', #{keyword}, '%')
        or o.objective_name like concat('%', #{keyword}, '%')
        or o.objective_code like concat('%', #{keyword}, '%')
        or m.model_name like concat('%', #{keyword}, '%')
        or cls.class_name like concat('%', #{keyword}, '%')
        or s.semester_name like concat('%', #{keyword}, '%')
    )

